// Fontes da identidade Pazelli embutidas em base64 (mesmo padrão dos
// assets de imagem) — evita depender de rede em tempo de renderização na
// função serverless. Poppins (OFL) via github.com/google/fonts.
import { Font } from "@react-pdf/renderer";

const poppinsSemiBold = "data:font/ttf;base64,";
const poppinsBold = "data:font/ttf;base64,";

let registrado = false;

/** Registra a família "Poppins" (600/700). Idempotente. */
export function registrarFontesPazelli() {
  if (registrado) return;
  Font.register({
    family: "Poppins",
    fonts: [
      { src: poppinsSemiBold, fontWeight: 600 },
      { src: poppinsBold, fontWeight: 700 },
    ],
  });
  registrado = true;
}
